                            if ((requiredPropertyChildHandler_seenItems[RequiredOffsetForProjectId] & RequiredBitForProjectId) == 0)
                            {
                                context.EvaluatedKeywordForProperty(false, 7, RequiredPropertyProjectIdNotPresent, "projectId"u8, "required"u8);
                            }
                            else
                            {
                                context.EvaluatedKeywordForProperty(true, 7, RequiredPropertyProjectIdPresent, "projectId"u8, "required"u8);
                            }

                            if ((requiredPropertyChildHandler_seenItems[RequiredOffsetForRunId] & RequiredBitForRunId) == 0)
                            {
                                context.EvaluatedKeywordForProperty(false, 8, RequiredPropertyRunIdNotPresent, "runId"u8, "required"u8);
                            }
                            else
                            {
                                context.EvaluatedKeywordForProperty(true, 8, RequiredPropertyRunIdPresent, "runId"u8, "required"u8);
                            }

                            if ((requiredPropertyChildHandler_seenItems[RequiredOffsetForSchemaVersion] & RequiredBitForSchemaVersion) == 0)
                            {
                                context.EvaluatedKeywordForProperty(false, 9, RequiredPropertySchemaVersionNotPresent, "schemaVersion"u8, "required"u8);
                            }
                            else
                            {
                                context.EvaluatedKeywordForProperty(true, 9, RequiredPropertySchemaVersionPresent, "schemaVersion"u8, "required"u8);
                            }
                        }
                    }
                }

                internal static bool Evaluate(
                    IJsonDocument parentDocument,
                    int parentIndex,
                    IJsonSchemaResultsCollector? resultsCollector = null)
                {
                    JsonSchemaContext context = JsonSchemaContext.BeginContext(
                    parentDocument,
                    parentIndex,
                    usingEvaluatedItems: false,
                    usingEvaluatedProperties: true,
                    resultsCollector: resultsCollector);
                    try
                    {
                        Evaluate(parentDocument, parentIndex, ref context);
                        context.EndContext();
                        return context.IsMatch;
                    }
                    finally
                    {
                        context.Dispose();
                    }
                }

                /// <summary>
                /// Push the current context as a child context for schema evaluation.
